const body = $input.first().json.body;
const message = body.message;
const toolCall = message.toolCallList?.[0] || {};
const toolCallId = toolCall.id || '';
const args = toolCall.function?.arguments || {};

// Normalize US phone to E.164
let phone = (args.phone_number || '').trim();
let error = '';
if (phone) {
  const digits = phone.replace(/\D/g, '');
  if (digits.length === 10) phone = '+1' + digits;
  else if (digits.length === 11 && digits[0] === '1') phone = '+' + digits;
  else if (phone.startsWith('+') && digits.length >= 10) phone = '+' + digits;
  else { error = 'invalid_phone'; phone = ''; }
}

const lastName = (args.last_name || '').trim();
const claimNumber = (args.claim_number || '').trim();

if (!phone && !lastName && !claimNumber && !error) {
  error = 'no_params';
}

// Build PostgREST OR filter string for Supabase node.
// Use phone_digits (generated column, strips '+') to avoid the
// Supabase node's encodeURI() mangling '+' in E.164 numbers.
const conditions = [];
if (phone) conditions.push(`phone_digits.eq.${phone.replace('+', '')}`);
if (lastName) conditions.push(`last_name.ilike.${lastName}`);
if (claimNumber) conditions.push(`claim_number.ilike.${claimNumber}`);
const filterString = conditions.length > 0 ? `or=(${conditions.join(',')})` : '';

return [{
  json: {
    toolCallId,
    phone_number: phone,
    last_name: lastName,
    claim_number: claimNumber,
    filterString,
    error
  }
}];

const envelope = $('Parse Envelope').first().json;
const toolCallId = envelope.toolCallId;
const error = envelope.error;

let result;
if (error === 'invalid_phone') {
  result = { found: false, error: true, message: 'The phone number provided appears to be invalid. Please ask the caller to provide their full phone number.' };
} else if (error === 'no_params') {
  result = { found: false, error: true, message: 'No search parameters provided. Please provide a phone number, last name, or claim number.' };
} else {
  const rows = $input.all().map(i => i.json).filter(r => r.id);
  if (rows.length === 0) {
    result = { found: false, message: 'No matching record found in our system.' };
  } else if (rows.length === 1) {
    const r = rows[0];
    result = {
      found: true, multiple: false,
      first_name: r.first_name, last_name: r.last_name,
      claim_number: r.claim_number, claim_status: r.claim_status,
      claim_details: r.claim_details || '', phone_number: r.phone_number,
      date_of_birth: r.date_of_birth || ''
    };
  } else {
    result = {
      found: true, multiple: true,
      matches: rows.map(r => ({
        first_name: r.first_name, last_name: r.last_name,
        claim_number: r.claim_number, claim_status: r.claim_status
      }))
    };
  }
}

return [{
  json: {
    results: [{ toolCallId, result: JSON.stringify(result) }]
  }
}];
